import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"전자결재 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/e-approval.md","filePath":"guide/scenarios/e-approval.md","lastUpdated":null}'),e={name:"guide/scenarios/e-approval.md"};function i(s,a,n,h,d,p){return l(),r("div",null,[...a[0]||(a[0]=[o(`<h1 id="전자결재-처리" tabindex="-1">전자결재 처리 <a class="header-anchor" href="#전자결재-처리" aria-label="Permalink to &quot;전자결재 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 5분 | <strong>난이도</strong>: ★☆☆ | <strong>주기</strong>: 수시</p></blockquote><p>문서를 작성하고 결재선을 지정하여 상신한 뒤, 결재자가 승인 또는 반려하는 전자결재 프로세스입니다. 완료된 문서는 Xp문서함에 자동 보관됩니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 결재라인 사전 설정   (최초 1회)  → 단지관리에서 결재라인 등록</span></span>
<span class="line"><span>2. 문서 작성 (기안)     (3분)       → 장표 종류 선택 후 내용 입력</span></span>
<span class="line"><span>3. 결재선 지정          (1분)       → 결재자 순서 지정</span></span>
<span class="line"><span>4. 상신                 (1분)       → 결재 요청 전송</span></span>
<span class="line"><span>5. 결재자 승인/반려     (수신자)    → 결재자가 검토 후 처리</span></span>
<span class="line"><span>6. 완료 문서 보관       (자동)      → Xp문서함에 자동 저장</span></span></code></pre></div><hr><h2 id="사전-준비-결재라인-등록-최초-1회" tabindex="-1">사전 준비: 결재라인 등록 (최초 1회) <a class="header-anchor" href="#사전-준비-결재라인-등록-최초-1회" aria-label="Permalink to &quot;사전 준비: 결재라인 등록 (최초 1회)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 단지관리 &gt; 단지정보 &gt; 결재라인등록 (DANG0051)</p></blockquote><p>전자결재를 사용하기 전에 결재 흐름(누가 누구에게 결재를 받는지)을 먼저 설정합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>결재라인등록 화면 진입</li><li><strong>장표 종류</strong> 선택:</li></ol><table tabindex="0"><thead><tr><th>장표 종류</th><th>설명</th></tr></thead><tbody><tr><td>지출결의서</td><td>지출 승인 요청</td></tr><tr><td>품의서</td><td>업무 사항 결재</td></tr><tr><td>보고서</td><td>업무 보고</td></tr><tr><td>기타</td><td>단지별 설정</td></tr></tbody></table><ol start="3"><li>해당 장표에 결재라인 등록: <ul><li>결재자 직급·이름 순서대로 추가</li><li>합의자·수신자(참조) 추가 (해당 시)</li></ul></li><li><strong>저장</strong> 클릭</li></ol><div class="tip custom-block"><p class="custom-block-title">결재라인은 장표 종류별로 설정</p><p>장표 종류(지출결의서, 품의서 등)마다 별도의 결재라인을 등록할 수 있습니다. 업무 유형에 따라 결재 경로가 다를 때 활용하세요.</p></div><hr><h2 id="_1단계-문서-작성-기안-3분" tabindex="-1">1단계: 문서 작성 (기안) (3분) <a class="header-anchor" href="#_1단계-문서-작성-기안-3분" aria-label="Permalink to &quot;1단계: 문서 작성 (기안) (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: Xp전자결재 &gt; <a href="/appr/">전자결재</a></p></blockquote><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전자결재 화면 진입</li><li><strong>문서 작성</strong> 또는 <strong>기안</strong> 클릭</li><li><strong>장표 종류</strong> 선택 (지출결의서, 품의서 등)</li><li>문서 내용 입력:</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td><strong>제목</strong></td><td>문서의 제목</td></tr><tr><td><strong>내용</strong></td><td>결재 요청 내용 상세 기술</td></tr><tr><td><strong>금액</strong></td><td>지출결의서의 경우 금액 입력</td></tr><tr><td><strong>첨부파일</strong></td><td>관련 증빙 자료 첨부 (선택)</td></tr></tbody></table><ol start="5"><li>내용 확인 후 다음 단계로 이동</li></ol><hr><h2 id="_2단계-결재선-지정-1분" tabindex="-1">2단계: 결재선 지정 (1분) <a class="header-anchor" href="#_2단계-결재선-지정-1분" aria-label="Permalink to &quot;2단계: 결재선 지정 (1분)&quot;">​</a></h2><p>문서 작성 화면에서 결재선을 지정합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li><strong>결재선</strong> 항목에서 <strong>결재라인 불러오기</strong> 클릭</li><li>사전 등록된 결재라인 선택</li><li>필요 시 이번 문서에만 결재자 추가·변경</li><li>결재 순서 확인</li></ol><h3 id="결재선-구성" tabindex="-1">결재선 구성 <a class="header-anchor" href="#결재선-구성" aria-label="Permalink to &quot;결재선 구성&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>설명</th></tr></thead><tbody><tr><td><strong>결재자</strong></td><td>승인 권한이 있는 결재 담당자 (순서대로 결재)</td></tr><tr><td><strong>합의자</strong></td><td>결재 과정에 의견을 제시하는 참여자</td></tr><tr><td><strong>수신자</strong></td><td>결재 완료 후 문서를 공유받는 참조자</td></tr></tbody></table><hr><h2 id="_3단계-상신-1분" tabindex="-1">3단계: 상신 (1분) <a class="header-anchor" href="#_3단계-상신-1분" aria-label="Permalink to &quot;3단계: 상신 (1분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: Xp전자결재 &gt; <a href="/appr/">전자결재</a> &gt; 상신</p></blockquote><ol><li>문서 내용과 결재선 최종 확인</li><li><strong>상신</strong> 버튼 클릭</li><li>첫 번째 결재자에게 알림 전송</li></ol><div class="warning custom-block"><p class="custom-block-title">상신 후 수정 불가</p><p>상신 이후에는 문서 내용을 <strong>수정할 수 없습니다</strong>. 상신 전에 내용과 첨부파일을 반드시 확인하세요. 수정이 필요하면 결재자에게 반려 요청 후 재작성해야 합니다.</p></div><hr><h2 id="_4단계-결재자-승인-반려-결재자" tabindex="-1">4단계: 결재자 승인/반려 (결재자) <a class="header-anchor" href="#_4단계-결재자-승인-반려-결재자" aria-label="Permalink to &quot;4단계: 결재자 승인/반려 (결재자)&quot;">​</a></h2><p>결재 요청을 받은 결재자가 처리합니다.</p><h3 id="승인-절차" tabindex="-1">승인 절차 <a class="header-anchor" href="#승인-절차" aria-label="Permalink to &quot;승인 절차&quot;">​</a></h3><ol><li>전자결재 수신함에서 해당 문서 선택</li><li>내용 검토</li><li><strong>승인</strong> 클릭 → 다음 결재자에게 자동 이관 (또는 최종 승인 처리)</li></ol><h3 id="반려-절차" tabindex="-1">반려 절차 <a class="header-anchor" href="#반려-절차" aria-label="Permalink to &quot;반려 절차&quot;">​</a></h3><ol><li>전자결재 수신함에서 해당 문서 선택</li><li>내용 검토</li><li><strong>반려</strong> 클릭 → 반려 사유 입력</li><li>기안자에게 반려 알림 전송</li></ol><div class="tip custom-block"><p class="custom-block-title">반려 후 재기안</p><p>반려된 문서는 수정 후 새로 기안하여 상신해야 합니다.</p></div><hr><h2 id="_5단계-완료-문서-보관-자동" tabindex="-1">5단계: 완료 문서 보관 (자동) <a class="header-anchor" href="#_5단계-완료-문서-보관-자동" aria-label="Permalink to &quot;5단계: 완료 문서 보관 (자동)&quot;">​</a></h2><p>모든 결재자의 승인이 완료되면 문서가 자동으로 Xp문서함에 저장됩니다.</p><blockquote><p><strong>메뉴 경로</strong>: <a href="/docs-menu/">Xp문서함</a></p></blockquote><h3 id="문서함-활용" tabindex="-1">문서함 활용 <a class="header-anchor" href="#문서함-활용" aria-label="Permalink to &quot;문서함 활용&quot;">​</a></h3><ol><li>Xp문서함 화면 진입</li><li>검색 조건 입력 (기간, 장표 종류, 제목, 기안자 등)</li><li>해당 문서 선택 후 열람·출력</li></ol><hr><h2 id="아파트뱅크-이체-연계" tabindex="-1">아파트뱅크 이체 연계 <a class="header-anchor" href="#아파트뱅크-이체-연계" aria-label="Permalink to &quot;아파트뱅크 이체 연계&quot;">​</a></h2><p>지출결의서 결재 완료 후 실제 이체로 이어지는 흐름입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>지출결의서 작성 → 결재 완료 → 아파트뱅크 이체 실행</span></span></code></pre></div><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a></p></blockquote><ol><li>지출결의서 전자결재 완료</li><li>아파트뱅크 이체 화면에서 해당 결의서 연계</li><li>이체 실행 (공인인증서 서명)</li><li>이체 결과 확인</li></ol><div class="tip custom-block"><p class="custom-block-title">결재와 이체를 연계하면</p><p>지출 승인과 실제 이체가 시스템으로 연결되어 <strong>이중 확인</strong>이 되므로 횡령·오류 예방에 효과적입니다.</p></div><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="결재라인이-자동으로-불러와지지-않아요" tabindex="-1">결재라인이 자동으로 불러와지지 않아요 <a class="header-anchor" href="#결재라인이-자동으로-불러와지지-않아요" aria-label="Permalink to &quot;결재라인이 자동으로 불러와지지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 결재라인등록(DANG0051)에서 해당 장표 종류의 결재라인이 등록되지 않은 경우 <strong>해결</strong>: 단지관리 &gt; 단지정보 &gt; 결재라인등록에서 장표 종류별 결재라인을 먼저 등록하세요.</p><h3 id="상신한-문서를-수정해야-해요" tabindex="-1">상신한 문서를 수정해야 해요 <a class="header-anchor" href="#상신한-문서를-수정해야-해요" aria-label="Permalink to &quot;상신한 문서를 수정해야 해요&quot;">​</a></h3><p><strong>원인</strong>: 상신 후 내용 오류 발견 <strong>해결</strong>: 현재 결재 중인 결재자에게 <strong>반려</strong> 요청을 합니다. 반려 후 문서를 수정하여 새로 기안·상신하세요.</p><h3 id="결재-완료-문서가-xp문서함에서-보이지-않아요" tabindex="-1">결재 완료 문서가 Xp문서함에서 보이지 않아요 <a class="header-anchor" href="#결재-완료-문서가-xp문서함에서-보이지-않아요" aria-label="Permalink to &quot;결재 완료 문서가 Xp문서함에서 보이지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 검색 기간 또는 조건이 맞지 않는 경우 <strong>해결</strong>: Xp문서함에서 검색 기간을 넓히거나, 장표 종류·제목으로 다시 검색하세요.</p><h3 id="반려된-문서를-다시-올리고-싶어요" tabindex="-1">반려된 문서를 다시 올리고 싶어요 <a class="header-anchor" href="#반려된-문서를-다시-올리고-싶어요" aria-label="Permalink to &quot;반려된 문서를 다시 올리고 싶어요&quot;">​</a></h3><p><strong>원인</strong>: 결재자 반려 후 재상신 필요 <strong>해결</strong>: 반려 사유를 확인하고 내용을 수정한 뒤, <strong>새 문서로 기안</strong>하여 다시 상신하세요. 반려된 문서는 직접 수정하여 재상신할 수 없습니다.</p><hr><h2 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h2><h3 id="기안-전" tabindex="-1">기안 전 <a class="header-anchor" href="#기안-전" aria-label="Permalink to &quot;기안 전&quot;">​</a></h3><ul><li>[ ] 장표 종류가 맞는가?</li><li>[ ] 결재 내용이 정확하고 충분한가?</li><li>[ ] 첨부 증빙 자료가 준비되었는가?</li><li>[ ] 결재선(결재자 순서)이 올바른가?</li></ul><h3 id="상신-후" tabindex="-1">상신 후 <a class="header-anchor" href="#상신-후" aria-label="Permalink to &quot;상신 후&quot;">​</a></h3><ul><li>[ ] 첫 번째 결재자에게 알림이 전송되었는가?</li><li>[ ] 결재 진행 상태를 확인했는가?</li></ul><h3 id="결재-완료-후" tabindex="-1">결재 완료 후 <a class="header-anchor" href="#결재-완료-후" aria-label="Permalink to &quot;결재 완료 후&quot;">​</a></h3><ul><li>[ ] Xp문서함에 문서가 저장되었는가?</li><li>[ ] 지출결의서라면 아파트뱅크 이체가 실행되었는가?</li></ul><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/appr/">전자결재</a> - 전자결재 기안·결재 처리</li><li><a href="/docs-menu/">Xp문서함</a> - 완료 문서 보관·조회</li><li><a href="/bank/transfer.html">아파트뱅크 이체</a> - 지출결의서 이체 연계</li><li><a href="/dang/">단지관리</a> - 결재라인등록 (DANG0051)</li></ul>`,75)])])}const g=t(e,[["render",i]]);export{u as __pageData,g as default};
